        {"name": "Net Present Value (NPV)", "desc": "Sum of discounted cash flows", "params": "CF_t ($), i (dimensionless), n (years)", "eq": "NPV = Σ CF_t / (1+i)^t", "unit": "$", "purpose": "Evaluate project economic viability"},
        {"name": "Internal Rate of Return (IRR)", "desc": "Discount rate where NPV = 0", "params": "CF_t ($), IRR (dimensionless)", "eq": "0 = Σ CF_t / (1+IRR)^t", "unit": "dimensionless", "purpose": "Compare project profitability"},
        {"name": "Bare Module Cost (Lang Factor)", "desc": "Equipment cost including installation", "params": "C_p ($), F_BM (dimensionless)", "eq": "C_BM = C_p × F_BM", "unit": "$", "purpose": "Estimate installed equipment cost"},
        {"name": "Chemical Engineering Plant Cost Index (CEPCI)", "desc": "Update historical costs to present", "params": "C_old ($), I_new (dimensionless), I_old (dimensionless)", "eq": "C_new = C_old × (I_new/I_old)", "unit": "$", "purpose": "Adjust costs for inflation"},
        {"name": "Six-Tenths Rule (Capacity Scaling)", "desc": "Scale equipment cost with capacity", "params": "C₁ ($), Q₁ (units), Q₂ (units), n (dimensionless)", "eq": "C₂ = C₁ × (Q₂/Q₁)^n", "unit": "$", "purpose": "Estimate cost for different capacities"},
        {"name": "Heat Exchanger Area (Design)", "desc": "Required heat transfer area", "params": "Q (W), U (W/m²·K), ΔT_lm (K)", "eq": "A = Q/(U × ΔT_lm)", "unit": "m²", "purpose": "Size heat exchanger"},
        {"name": "Distillation Column Diameter", "desc": "Column diameter based on vapor flow", "params": "V (m³/s), ρ_v (kg/m³), u_flood (m/s), f (dimensionless)", "eq": "D = √[4V/(π × f × u_flood)]", "unit": "m", "purpose": "Size distillation column"},
        {"name": "Distillation Column Height", "desc": "Column height based on number of trays", "params": "N (dimensionless), tray_spacing (m)", "eq": "H = N × tray_spacing + extra (feed, disengagement)", "unit": "m", "purpose": "Estimate distillation column height"},
        {"name": "Pump Power (Design)", "desc": "Power required for pumping", "params": "Q (m³/s), ΔP (Pa), η (dimensionless), ρ (kg/m³)", "eq": "P = Q × ΔP / η", "unit": "W", "purpose": "Select pump motor size"},
        {"name": "Compressor Power (Isentropic)", "desc": "Power for gas compression", "params": "ṁ (kg/s), R (J/kg·K), T₁ (K), P₂/P₁ (dimensionless), γ (dimensionless), η (dimensionless)", "eq": "P = ṁ × [γRT₁/(γ-1)] × [(P₂/P₁)^{(γ-1)/γ} - 1]/η", "unit": "W", "purpose": "Size compressor"},
        {"name": "Reactor Volume (CSTR Design)", "desc": "Volume for Continuous Stirred Tank Reactor", "params": "F_A0 (mol/s), X (dimensionless), -r_A (mol/m³·s)", "eq": "V = F_A0 × X / (-r_A)", "unit": "m³", "purpose": "Size CSTR reactor"},
        {"name": "Reactor Volume (PFR Design)", "desc": "Volume for Plug Flow Reactor", "params": "F_A0 (mol/s), X (dimensionless), -r_A (mol/m³·s)", "eq": "V = F_A0 ∫ dX/(-r_A)", "unit": "m³", "purpose": "Size PFR reactor"},
        {"name": "Storage Tank Volume", "desc": "Volume for liquid storage", "params": "Q (m³/s), t (s), f (dimensionless)", "eq": "V = Q × t × f", "unit": "m³", "purpose": "Size storage vessels"},
        {"name": "Pressure Vessel Wall Thickness", "desc": "Minimum wall thickness for cylindrical vessel", "params": "P (Pa), D (m), S (Pa), E (dimensionless), C (m)", "eq": "t = (P × D)/(2 × S × E - 1.2P) + C", "unit": "m", "purpose": "Design pressure vessel"},
